  1	import { Flex, FlexItem, Radio, Text, TextVariants } from '@patternfly/react-core';
  2	import * as React from 'react';
  3	import { useTranslation } from 'react-i18next';
  4	import { TopologyMetrics } from '../../../api/loki';
  5	import { isTimeMetric, MetricType } from '../../../model/flow-query';
  6	import { getStat } from '../../../model/metrics';
  7	import { decorated, NodeData } from '../../../model/topology';
  8	import { matchPeer } from '../../../utils/metrics';
  9	import { toNamedMetric } from '../../../utils/metrics-helper';
 10	import { TruncateLength } from '../../dropdowns/truncate-dropdown';
 11	import { MetricsGraph } from '../../metrics/metrics-graph';
 12	import { ElementPanelStats } from './element-panel-stats';
 13	
 14	type MetricsRadio = 'in' | 'out' | 'both';
 15	
 16	export interface ElementPanelMetricsProps {
 17	  aData: NodeData;
 18	  bData?: NodeData;
 19	  isGroup: boolean;
 20	  metrics: TopologyMetrics[];
 21	  metricType: MetricType;
 22	  truncateLength: TruncateLength;
 23	}
 24	
 25	export const ElementPanelMetrics: React.FC<ElementPanelMetricsProps> = ({
 26	  aData,
 27	  bData,
 28	  isGroup,
 29	  metrics,
 30	  metricType,
 31	  truncateLength
 32	}) => {
 33	  const { t } = useTranslation('plugin__netobserv-plugin');
 34	  const [metricsRadio, setMetricsRadio] = React.useState<MetricsRadio>('both');
 35	
 36	  const useArea = !isTimeMetric(metricType);
 37	  const titleStats = t('Stats');
 38	
 39	  let id = '';
 40	  let metricsIn: TopologyMetrics[] = [];
 41	  let metricsOut: TopologyMetrics[] = [];
 42	  let metricsBoth: TopologyMetrics[] = [];
 43	
 44	  if (bData) {
 45	    // Edge selected
 46	    id = `edge-${aData.peer.id}-${bData!.peer.id}`;
 47	    metricsIn = metrics.filter(m => matchPeer(aData, m.source) && matchPeer(bData, m.destination));
 48	    metricsOut = metrics.filter(m => matchPeer(bData, m.source) && matchPeer(aData, m.destination));
 49	    metricsBoth = [...metricsIn, ...metricsOut];
 50	  } else {
 51	    // Node or group selected
 52	    id = `node-${decorated(aData).id}`;
 53	    metricsIn = metrics.filter(m => m.source.id !== m.destination.id && matchPeer(aData, m.destination));
 54	    metricsOut = metrics.filter(m => m.source.id !== m.destination.id && matchPeer(aData, m.source));
 55	    // Note that metricsBoth is not always the concat of in+out:
 56	    //  when a group is selected, there might be an overlap of in and out, so we don't want to count them twice
 57	    metricsBoth = metrics.filter(
 58	      m => m.source.id !== m.destination.id && (matchPeer(aData, m.source) || matchPeer(aData, m.destination))
 59	    );
 60	  }
 61	  const focusNode = bData ? undefined : aData;
 62	  const top5 = (metricsRadio === 'in' ? metricsIn : metricsRadio === 'out' ? metricsOut : metricsBoth)
 63	    .map(m => toNamedMetric(t, m, truncateLength, false, false, isGroup ? undefined : focusNode))
 64	    .sort((a, b) => getStat(b.stats, 'sum') - getStat(a.stats, 'sum'));
 65	
 66	  const getChartTitle = React.useCallback(() => {
 67	    switch (metricType) {
 68	      case 'DnsLatencyMs':
 69	        return t('Top 5 DNS latency');
 70	      case 'TimeFlowRttNs':
 71	        return t('Top 5 flow RTT');
 72	      default:
 73	        return t('Top 5 rates');
 74	    }
 75	  }, [metricType, t]);
 76	
 77	  return (
 78	    <div className="element-metrics-container">
 79	      <FlexItem>
 80	        <Text id="metrics-stats-title" component={TextVariants.h4}>
 81	          {titleStats}
 82	        </Text>
 83	        <ElementPanelStats
 84	          metricType={metricType}
 85	          metricsIn={metricsIn}
 86	          metricsOut={metricsOut}
 87	          metricsBoth={metricsBoth}
 88	          isEdge={!!bData}
 89	        />
 90	      </FlexItem>
 91	      <FlexItem>
 92	        <Text id="metrics-chart-title" component={TextVariants.h4}>
 93	          {getChartTitle()}
 94	        </Text>
 95	        <Flex className="metrics-justify-content">
 96	          <FlexItem>
 97	            <Radio
 98	              isChecked={metricsRadio === 'in'}
 99	              name="radio-in"
100	              onChange={() => setMetricsRadio('in')}
101	              label={bData ? t('A -> B') : t('In')}
102	              id="radio-in"
103	            />
104	          </FlexItem>
105	          <FlexItem>
106	            <Radio
107	              isChecked={metricsRadio === 'out'}
108	              name="radio-out"
109	              onChange={() => setMetricsRadio('out')}
110	              label={bData ? t('B -> A') : t('Out')}
111	              id="radio-out"
112	            />
113	          </FlexItem>
114	          <FlexItem>
115	            <Radio
116	              isChecked={metricsRadio === 'both'}
117	              name="radio-both"
118	              onChange={() => setMetricsRadio('both')}
119	              label={t('Both')}
120	              id="radio-both"
121	            />
122	          </FlexItem>
123	        </Flex>
124	      </FlexItem>
125	      <MetricsGraph
126	        id={id}
127	        metricType={metricType}
128	        metricFunction={isTimeMetric(metricType) ? 'sum' : 'avg'}
129	        metrics={top5}
130	        limit={5}
131	        showArea={useArea}
132	        showLine={!useArea}
133	        showScatter
134	        tooltipsTruncate={true}
135	        showLegend={true}
136	      />
137	    </div>
138	  );
139	};

